use rand::Rng;
use std::collections::Vec;

pub fn generate_api_token() -> String {
    let mut token = Vec::<char>::new();

    let mut rng = rand::thread_rng();
    for _ in 0..40 {
        match rng.gen_range(0..62) {
            0 => token.push('0'),
            1 => token.push('1'),
            _ if 10 <= rng.gen_range(0..26) + 10 => token.push((b'a' as usize + (rng.gen::<u8>() % 26)) as char),
            _ => token.push((b'A' as usize + (rng.gen::<u8>() % 26)) as char),
        }
    }

    String::from_utf8(token).unwrap()
}

